import type { KcRagResponse } from '../context/kcrag'

export function isTier1(result: KcRagResponse | null): boolean {
  if (!result || result.tokens === 0) return false
  const isStrong = result.tokens > 300
  const taskType = result.task_type
  return isStrong && (
    taskType === 'code_query' || taskType === 'search' ||
    taskType === 'no_code' || taskType === 'refactor'
  )
}

import type { Status } from '../mcp'

export function getAvailableMcpToolNames(status: Status): string[] {
  if (status.status !== 'connected') return []
  // Status.connected no tiene campo tools directamente en el tipo
  // La implementación correcta requiere el Interface completo, no solo Status
  return []
}
// Nota: Status.connected solo tiene {status: 'connected'}, los tools están en Interface.tools
